    59→  case envoy::config::route::v3::HeaderMatcher::HeaderMatchSpecifierCase::kSafeRegexMatch:
    60→    header_match_type_ = HeaderMatchType::Regex;
    61→    regex_ = Regex::Utility::parseRegex(config.safe_regex_match(), factory_context.regexEngine());
    62→    break;
    63→  case envoy::config::route::v3::HeaderMatcher::HeaderMatchSpecifierCase::kRangeMatch:
    64→    header_match_type_ = HeaderMatchType::Range;
    65→    range_.set_start(config.range_match().start());
    66→    range_.set_end(config.range_match().end());
    67→    break;
    68→  case envoy::config::route::v3::HeaderMatcher::HeaderMatchSpecifierCase::kPresentMatch:
    69→    header_match_type_ = HeaderMatchType::Present;
    70→    present_ = config.present_match();
    71→    break;
    72→  case envoy::config::route::v3::HeaderMatcher::HeaderMatchSpecifierCase::kPrefixMatch:
    73→    header_match_type_ = HeaderMatchType::Prefix;
    74→    value_ = config.prefix_match();
    75→    break;
    76→  case envoy::config::route::v3::HeaderMatcher::HeaderMatchSpecifierCase::kSuffixMatch:
    77→    header_match_type_ = HeaderMatchType::Suffix;
    78→    value_ = config.suffix_match();
    79→    break;
    80→  case envoy::config::route::v3::HeaderMatcher::HeaderMatchSpecifierCase::kContainsMatch:
    81→    header_match_type_ = HeaderMatchType::Contains;
